import React, { useState } from "react";
import "./Login.css"; // keep your UI

function Login() {
  const [empld, setEmpld] = useState("");
  const [password, setPassword] = useState("");

  const handleLogin = async (e) => {
    e.preventDefault();

    try {
      const res = await fetch("https://prasa-app-yde3.onrender.com/api/login", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ empld, password }),
      });

      const data = await res.json();
      console.log("LOGIN RESPONSE:", data);

      if (!data.success) {
        alert(data.message || "Invalid login");
      } else {
        alert("Login successful");
      }
    } catch (err) {
      console.error("Login Error:", err);
      alert("Server error");
    }
  };

  return (
    <div className="login-wrapper">
      <div className="login-card">

        {/* ✔ FIXED LOGO PATH */}
        <img
          src="/prasa-logo.png"
          alt="Prasa Logo"
          className="login-logo"
        />

        <h2 className="login-title">PRASA Employee Portal</h2>

        <form onSubmit={handleLogin}>
          {/* Removed extra labels you did NOT want */}

          <input
            type="text"
            className="input-box"
            placeholder="EMP ID"
            value={empld}
            onChange={(e) => setEmpld(e.target.value)}
          />

          <input
            type="password"
            className="input-box"
            placeholder="Password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />

          <button type="submit" className="btn-login">
            Login
          </button>
        </form>
      </div>
    </div>
  );
}

export default Login;
